#!/bin/bash
# utils.sh

# Функция для удаления кавычек из строки
trim_quotes() {
    local string="$1"
    # Удаляем двойные кавычки с начала и конца строки
    string="${string#\"}"
    string="${string%\"}"
    # Удаляем одинарные кавычки с начала и конца строки
    string="${string#\'}"
    string="${string%\'}"
    echo "$string"
}

# Экранирует текст для Telegram MarkdownV2.
# В MarkdownV2 есть специальный список символов, которые нужно экранировать
# обратным слешем, иначе Telegram может вернуть:
# "can't parse entities".
# Функция делает экранирование централизованно, чтобы использовать один
# безопасный и предсказуемый способ во всех workflow-скриптах.
escape_markdown_v2() {
    local input="$1"
    # ВАЖНО: сначала экранируем "\". Иначе последующие замены могут сломаться.
    # Далее экранируем все спецсимволы MarkdownV2 из документации Telegram:
    # _ * [ ] ( ) ~ ` > # + - = | { } . !
    printf '%s' "$input" | sed \
        -e 's/\\/\\\\/g' \
        -e 's/_/\\_/g' \
        -e 's/\*/\\*/g' \
        -e 's/\[/\\[/g' \
        -e 's/\]/\\]/g' \
        -e 's/(/\\(/g' \
        -e 's/)/\\)/g' \
        -e 's/~/\\~/g' \
        -e 's/`/\\`/g' \
        -e 's/>/\\>/g' \
        -e 's/#/\\#/g' \
        -e 's/+/\\+/g' \
        -e 's/-/\\-/g' \
        -e 's/=/\\=/g' \
        -e 's/|/\\|/g' \
        -e 's/{/\\{/g' \
        -e 's/}/\\}/g' \
        -e 's/\./\\./g' \
        -e 's/!/\\!/g'
}
